6	//! Nested-module `#[cuda_module]` example.
7	//!
8	//! Kernels live at three levels of inline nesting:
9	//!
10	//! - `init::fill_index`, `scale::scale_by`, and `offset::offset_by` one level
11	//!   down,
12	//! - `post::double::double_all` two levels down.
13	//!
14	//! Each namespace owns a `LoadedModule` launcher view. Child views borrow the
15	//! same loaded CUDA module through `LoadedModule::from_parent`.
16	//!
17	//! Build and run with:
18	//!   cargo oxide run cuda_module_nested
19	
20	use cuda_core::{CudaContext, DeviceBuffer, LaunchConfig};
21	use cuda_device::cuda_module;
22	
23	#[cuda_module]
24	mod kernels {
25	    /// Inline nested module: out[i] = i.
26	    ///
27	    /// The root intentionally has no direct kernel. This checks that calling
28	    /// `kernels::load()` still pins an artifact owned entirely by descendants.
29	    pub mod init {
30	        use cuda_device::{DisjointSlice, kernel, thread};
31	
32	        #[kernel]
33	        pub fn fill_index(mut out: DisjointSlice<f32>) {
34	            let idx = thread::index_1d();
35	            let idx_raw = idx.get();
36	            if let Some(elem) = out.get_mut(idx) {
37	                *elem = idx_raw as f32;
38	            }
39	        }
40	    }
41	
42	    /// Inline nested module: out[i] = a[i] * 2
43	    pub mod scale {
44	        use cuda_device::{DisjointSlice, kernel, thread};
45	
46	        #[kernel]
47	        pub fn scale_by(a: &[f32], mut out: DisjointSlice<f32>) {
48	            let idx = thread::index_1d();
49	            let idx_raw = idx.get();
50	            if let Some(elem) = out.get_mut(idx) {
51	                *elem = a[idx_raw] * 2.0;
52	            }
53	        }
54	    }
55	
56	    /// Inline nested module: out[i] = a[i] + 10
57	    pub mod offset {
58	        use cuda_device::{DisjointSlice, kernel, thread};
59	
60	        #[kernel]
61	        pub fn offset_by(a: &[f32], mut out: DisjointSlice<f32>) {
62	            let idx = thread::index_1d();
63	            let idx_raw = idx.get();
64	            if let Some(elem) = out.get_mut(idx) {
65	                *elem = a[idx_raw] + 10.0;
66	            }
67	        }
68	    }
69	
70	    /// An empty bridge namespace containing a doubly nested kernel module.
71	    pub mod post {
72	        pub mod double {
73	            use cuda_device::{DisjointSlice, kernel, thread};
74	
75	            #[kernel]
76	            pub fn double_all(a: &[f32], mut out: DisjointSlice<f32>) {
77	                let idx = thread::index_1d();
78	                let idx_raw = idx.get();
79	                if let Some(elem) = out.get_mut(idx) {
80	                    *elem = a[idx_raw] + a[idx_raw];
81	                }
82	            }
83	        }
84	    }
85	}
86	
87	fn main() {
88	    println!("=== #[cuda_module] Nested Modules Test ===\n");
89	
90	    let ctx = CudaContext::new(0).expect("Failed to create CUDA context");
91	    let stream = ctx.default_stream();
92	
93	    const N: usize = 1024;
94	    let mut idx_dev = DeviceBuffer::<f32>::zeroed(&stream, N).unwrap();
95	    let mut scaled_dev = DeviceBuffer::<f32>::zeroed(&stream, N).unwrap();
96	    let mut offset_dev = DeviceBuffer::<f32>::zeroed(&stream, N).unwrap();
97	    let mut doubled_dev = DeviceBuffer::<f32>::zeroed(&stream, N).unwrap();
98	
99	    let module = kernels::load(&ctx).expect("Failed to load embedded CUDA module");
100	    let init =
101	        kernels::init::LoadedModule::from_parent(&module).expect("Failed to bind init launchers");
102	    let scale =
103	        kernels::scale::LoadedModule::from_parent(&module).expect("Failed to bind scale launchers");
104	    let offset = kernels::offset::LoadedModule::from_parent(&module)
105	        .expect("Failed to bind offset launchers");
106	    let post =
107	        kernels::post::LoadedModule::from_parent(&module).expect("Failed to bind post launchers");
108	    let double = kernels::post::double::LoadedModule::from_parent(&post)
109	        .expect("Failed to bind double launchers");
110	    let config = LaunchConfig::for_num_elems(N as u32);
111	
112	    // SAFETY: every launch is one-dimensional over N elements, and each
113	    // input/output buffer covers the full range accessed by its kernel.
114	    unsafe {
115	        // The init kernel feeds the three processing kernels.
116	        init.fill_index(&stream, config, &mut idx_dev)
117	            .expect("fill_index launch failed");
118	        scale
119	            .scale_by(&stream, config, &idx_dev, &mut scaled_dev)
120	            .expect("scale_by launch failed");
121	        offset
122	            .offset_by(&stream, config, &idx_dev, &mut offset_dev)
123	            .expect("offset_by launch failed");
124	        double
125	            .double_all(&stream, config, &idx_dev, &mut doubled_dev)
126	            .expect("double_all launch failed");
127	    }
128	
129	    let scaled = scaled_dev.to_host_vec(&stream).unwrap();
130	    let offset = offset_dev.to_host_vec(&stream).unwrap();
131	    let doubled = doubled_dev.to_host_vec(&stream).unwrap();
132	
133	    let mut errors = 0;
134	    for i in 0..N {
135	        let expected_scaled = i as f32 * 2.0;
136	        let expected_offset = i as f32 + 10.0;
137	        let expected_doubled = i as f32 + i as f32;
138	        if (scaled[i] - expected_scaled).abs() > 1e-5
139	            || (offset[i] - expected_offset).abs() > 1e-5
140	            || (doubled[i] - expected_doubled).abs() > 1e-5
141	        {
142	            if errors < 5 {
143	                eprintln!(
144	                    "  Error at [{i}]: scaled {} (want {expected_scaled}), offset {} (want {expected_offset}), doubled {} (want {expected_doubled})",
145	                    scaled[i], offset[i], doubled[i],
146	                );
147	            }
148	            errors += 1;
149	        }
150	    }
151	
152	    if errors == 0 {
153	        println!("✓ SUCCESS: root-loaded nested inline kernels all ran");
154	    } else {
155	        println!("✗ FAILED: {errors} errors");
156	        std::process::exit(1);
157	    }
158	}
