    pub const fn new(grid_x: u32, block_x: u32, shared_mem_bytes: u32) -> Self {
        Self {
            grid_x,
            block_x,
            shared_mem_bytes,
        }
    }
}

impl sealed::Sealed for LaunchConfig1D {}

impl KernelLaunchConfig for LaunchConfig1D {
